using System.Collections.ObjectModel;
using System.Text.Json;
using SystemChecker.Models;
using SystemChecker.Services;

namespace SystemChecker.ViewModels;

public sealed class TelemetryV4ViewModel : ObservableObject, IDisposable
{
    private readonly SystemMetricsService _metrics=new();private readonly SensorMonitorService _sensors=new();private readonly HardwareInventoryService _inventory=new();private readonly DiagnosticsService _diagnostics=new();private readonly ExtendedBenchmarkService _benchmark=new();private readonly HealthService _health=new();private readonly HistoryRepository _history=new();private readonly EnhancedReportService _reports=new();
    private string _statusText="초기화 중",_cpuValue="—",_cpuDetail="표본 수집 중",_memoryValue="—",_memoryDetail="표본 수집 중",_diskValue="—",_diskDetail="표본 수집 중",_networkValue="—",_networkDetail="표본 수집 중",_temperatureValue="CPU — · GPU —",_sensorDetail="센서 초기화 중",_benchmarkStatus="테스트 준비됨",_overallScoreText="—",_gradeText="—",_cpuBenchmarkText="측정 전",_memoryBenchmarkText="측정 전",_diskBenchmarkText="측정 전",_gpuBenchmarkText="측정 전",_scoringBasis="CPU 35% + 메모리 20% + 디스크 25% + GPU 20%",_batteryText="조회 중",_historyStatus="기록 준비 중";
    private double _cpuScoreBar,_memoryScoreBar,_overallScoreBar,_diskScoreBar,_gpuScoreBar,_benchmarkProgress,_previousUsedMemoryMb;private bool _isBenchmarkRunning;private DateTimeOffset _lastHistoryWrite=DateTimeOffset.MinValue;private FullBenchmarkResult? _lastBenchmark;private HealthSnapshot? _healthSnapshot;
    public ObservableCollection<HardwareItem> HardwareItems{get;}=[];public ObservableCollection<DiagnosticItem> Diagnostics{get;}=[];public ObservableCollection<double> CpuHistory{get;}=[];public ObservableCollection<double> MemoryHistory{get;}=[];public ObservableCollection<double> DiskHistory{get;}=[];public ObservableCollection<double> NetworkHistory{get;}=[];public ObservableCollection<StorageHealthItem> StorageHealth{get;}=[];public ObservableCollection<DiagnosticItem> DriverDiagnostics{get;}=[];public ObservableCollection<BenchmarkHistoryItem> BenchmarkHistory{get;}=[];
    public string StatusText{get=>_statusText;private set=>SetProperty(ref _statusText,value);}public string CpuValue{get=>_cpuValue;private set=>SetProperty(ref _cpuValue,value);}public string CpuDetail{get=>_cpuDetail;private set=>SetProperty(ref _cpuDetail,value);}public string MemoryValue{get=>_memoryValue;private set=>SetProperty(ref _memoryValue,value);}public string MemoryDetail{get=>_memoryDetail;private set=>SetProperty(ref _memoryDetail,value);}public string DiskValue{get=>_diskValue;private set=>SetProperty(ref _diskValue,value);}public string DiskDetail{get=>_diskDetail;private set=>SetProperty(ref _diskDetail,value);}public string NetworkValue{get=>_networkValue;private set=>SetProperty(ref _networkValue,value);}public string NetworkDetail{get=>_networkDetail;private set=>SetProperty(ref _networkDetail,value);}public string TemperatureValue{get=>_temperatureValue;private set=>SetProperty(ref _temperatureValue,value);}public string SensorDetail{get=>_sensorDetail;private set=>SetProperty(ref _sensorDetail,value);}public string BenchmarkStatus{get=>_benchmarkStatus;private set=>SetProperty(ref _benchmarkStatus,value);}public double BenchmarkProgress{get=>_benchmarkProgress;private set=>SetProperty(ref _benchmarkProgress,value);}public bool IsBenchmarkRunning{get=>_isBenchmarkRunning;private set=>SetProperty(ref _isBenchmarkRunning,value);}public double CpuScoreBar{get=>_cpuScoreBar;private set=>SetProperty(ref _cpuScoreBar,value);}public double MemoryScoreBar{get=>_memoryScoreBar;private set=>SetProperty(ref _memoryScoreBar,value);}public double DiskScoreBar{get=>_diskScoreBar;private set=>SetProperty(ref _diskScoreBar,value);}public double GpuScoreBar{get=>_gpuScoreBar;private set=>SetProperty(ref _gpuScoreBar,value);}public double OverallScoreBar{get=>_overallScoreBar;private set=>SetProperty(ref _overallScoreBar,value);}public string OverallScoreText{get=>_overallScoreText;private set=>SetProperty(ref _overallScoreText,value);}public string GradeText{get=>_gradeText;private set=>SetProperty(ref _gradeText,value);}public string CpuBenchmarkText{get=>_cpuBenchmarkText;private set=>SetProperty(ref _cpuBenchmarkText,value);}public string MemoryBenchmarkText{get=>_memoryBenchmarkText;private set=>SetProperty(ref _memoryBenchmarkText,value);}public string DiskBenchmarkText{get=>_diskBenchmarkText;private set=>SetProperty(ref _diskBenchmarkText,value);}public string GpuBenchmarkText{get=>_gpuBenchmarkText;private set=>SetProperty(ref _gpuBenchmarkText,value);}public string ScoringBasis{get=>_scoringBasis;private set=>SetProperty(ref _scoringBasis,value);}public string BatteryText{get=>_batteryText;private set=>SetProperty(ref _batteryText,value);}public string HistoryStatus{get=>_historyStatus;private set=>SetProperty(ref _historyStatus,value);}public FullBenchmarkResult? LastBenchmark=>_lastBenchmark;public HealthSnapshot? CurrentHealth=>_healthSnapshot;
    public async Task InitializeAsync(CancellationToken token){await _history.InitializeAsync(token);foreach(var item in await _inventory.CollectAsync(token))HardwareItems.Add(item);await RefreshHealthAsync(token);await LoadHistoryAsync(token);await RefreshMetricsAsync(token);StatusText="모니터링 중 · 500ms";HistoryStatus=$"SQLite · {_history.DatabasePath}";}
    public async Task RefreshHealthAsync(CancellationToken token){_healthSnapshot=await _health.CaptureAsync(token);StorageHealth.Clear();foreach(var d in _healthSnapshot.Storage)StorageHealth.Add(d);DriverDiagnostics.Clear();foreach(var d in _healthSnapshot.DriverDiagnostics)DriverDiagnostics.Add(d);BatteryText=$"{_healthSnapshot.Battery.Status} · 충전 {_healthSnapshot.Battery.Charge} · 건강도 {_healthSnapshot.Battery.Health} · {_healthSnapshot.Battery.CycleCount} cycles";OnPropertyChanged(nameof(CurrentHealth));}
    public async Task RefreshMetricsAsync(CancellationToken token){var r=await Task.Run(()=>(_metrics.Capture(),_sensors.Capture()),token);Apply(r.Item1,r.Item2);if(DateTimeOffset.Now-_lastHistoryWrite>=TimeSpan.FromSeconds(5)){_lastHistoryWrite=DateTimeOffset.Now;await _history.AddTelemetryAsync(r.Item1,r.Item2,token);}}
    private void Apply(SystemSnapshot s,SensorSummary sensors){Append(CpuHistory,s.CpuUsagePercent);Append(MemoryHistory,s.MemoryUsagePercent);Append(DiskHistory,s.DiskReadMbps+s.DiskWriteMbps);Append(NetworkHistory,s.NetworkReceiveMbps+s.NetworkSendMbps);var used=s.UsedMemoryBytes/1048576d;var delta=_previousUsedMemoryMb==0?0:used-_previousUsedMemoryMb;_previousUsedMemoryMb=used;CpuValue=$"{s.CpuUsagePercent:0.0}%";CpuDetail=$"평균 {Avg(CpuHistory):0.0}% · 최고 {Max(CpuHistory):0.0}%";MemoryValue=$"{HardwareInventoryService.FormatBytes(s.UsedMemoryBytes)} / {HardwareInventoryService.FormatBytes(s.TotalMemoryBytes)}";MemoryDetail=$"{s.MemoryUsagePercent:0.0}% · 변화 {delta:+0.0;-0.0;0.0} MB";DiskValue=$"{s.DiskReadMbps+s.DiskWriteMbps:0.00} MB/s";DiskDetail=$"읽기 {s.DiskReadMbps:0.00} · 쓰기 {s.DiskWriteMbps:0.00} MB/s · 여유 {s.LowestDiskFreePercent:0.0}%";NetworkValue=$"{s.NetworkReceiveMbps+s.NetworkSendMbps:0.00} Mbps";NetworkDetail=$"수신 {s.NetworkReceiveMbps:0.00} · 송신 {s.NetworkSendMbps:0.00} Mbps";TemperatureValue=$"CPU {Sensor(sensors.CpuTemperature,"°C")} · GPU {Sensor(sensors.GpuTemperature,"°C")}";SensorDetail=sensors.StatusMessage+$" · 클럭 {Sensor(sensors.CpuClock,"MHz")} · 전력 {Sensor(sensors.CpuPower,"W")}";Diagnostics.Clear();foreach(var d in _diagnostics.Evaluate(s))Diagnostics.Add(d);if(!sensors.CpuTemperature.HasValue)Diagnostics.Insert(0,new("INFO","CPU 온도 센서 접근 불가",sensors.StatusMessage));}
    public async Task RunBenchmarkAsync(CancellationToken token){if(IsBenchmarkRunning)return;IsBenchmarkRunning=true;BenchmarkProgress=0;try{var previous=await _history.GetLatestScoreAsync(token);var r=await _benchmark.RunAsync(new Progress<string>(UpdateBenchmarkProgress),token);var comparison=previous.HasValue?$"이전 결과 대비 {r.OverallScore-previous:+#;-#;0}점":"첫 측정";_lastBenchmark=r with{Comparison=comparison};await _history.AddBenchmarkAsync(_lastBenchmark,token);ApplyBenchmark(_lastBenchmark);await LoadHistoryAsync(token);BenchmarkProgress=100;BenchmarkStatus=$"완료 · {comparison}";}catch(OperationCanceledException){BenchmarkProgress=0;BenchmarkStatus="취소됨";}finally{IsBenchmarkRunning=false;}}
    private void UpdateBenchmarkProgress(string value){BenchmarkStatus=value;BenchmarkProgress=CalculateBenchmarkProgress(value,BenchmarkProgress);}
    internal static double CalculateBenchmarkProgress(string value,double current)=>value switch{"워밍업 · CPU"=>5,"측정 중 · CPU SHA-256"=>15,"측정 중 · 메모리 대역폭"=>30,"완료"=>35,"DiskSpd · 순차 읽기"=>40,"DiskSpd · 순차 쓰기"=>55,"DiskSpd · 4K 랜덤 혼합"=>70,"GPU · WPF Direct3D 렌더링"=>90,_=>current};
    private void ApplyBenchmark(FullBenchmarkResult r){CpuScoreBar=Math.Min(r.CpuMemory.CpuScore,2000);MemoryScoreBar=Math.Min(r.CpuMemory.MemoryScore,2000);DiskScoreBar=Math.Min(r.Disk.Score,2000);GpuScoreBar=Math.Min(r.Gpu.Score,2000);OverallScoreBar=Math.Min(r.OverallScore,2000);OverallScoreText=r.OverallScore.ToString("N0");GradeText=r.Grade;CpuBenchmarkText=$"{r.CpuMemory.CpuScore:N0}점 · {r.CpuMemory.CpuThroughputMbps:N0} MiB/s";MemoryBenchmarkText=$"{r.CpuMemory.MemoryScore:N0}점 · {r.CpuMemory.MemoryBandwidthGbps:0.00} GB/s";DiskBenchmarkText=$"{r.Disk.Score:N0}점 · R/W {r.Disk.SequentialReadMbps:N0}/{r.Disk.SequentialWriteMbps:N0} MB/s · 4K {r.Disk.RandomReadIops:N0}/{r.Disk.RandomWriteIops:N0} IOPS";GpuBenchmarkText=$"{r.Gpu.Score:N0}점 · {r.Gpu.FramesPerSecond:0.0} FPS · {r.Gpu.MegaPixelsPerSecond:0.0} MPix/s · Tier {r.Gpu.RenderTier}";OnPropertyChanged(nameof(LastBenchmark));}
    private async Task LoadHistoryAsync(CancellationToken token){BenchmarkHistory.Clear();foreach(var h in await _history.GetBenchmarksAsync(20,token))BenchmarkHistory.Add(h);}
    public ReportSnapshot BuildReportSnapshot()=>EnhancedReportService.BuildSnapshot(HardwareItems,CurrentHealth,Diagnostics,LastBenchmark,BenchmarkHistory,CpuHistory,MemoryHistory,DiskHistory,NetworkHistory);
    public Task ExportJsonAsync(string path)=>_reports.ExportJsonAsync(path,BuildReportSnapshot());
    public void ExportPdf(string path)=>_reports.ExportPdf(path,BuildReportSnapshot());public void ExportHtml(string path)=>_reports.ExportHtml(path,BuildReportSnapshot());
    private static void Append(ObservableCollection<double> v,double x){v.Add(x);while(v.Count>120)v.RemoveAt(0);}private static double Avg(IEnumerable<double> v)=>v.Any()?v.Average():0;private static double Max(IEnumerable<double> v)=>v.Any()?v.Max():0;private static string Sensor(double? v,string unit)=>v.HasValue?$"{v:0.0}{unit}":"—";public void Dispose(){_metrics.Dispose();_sensors.Dispose();}
}
